mapper.select:
SELECT 
FROM openplatform_v2_cp_execution_record_t


        AND flow_id = #{flowId}


        AND app_id = #{appId}


        AND status = #{status}


        AND trigger_type = #{triggerType}


        AND (flow_name_cn LIKE CONCAT('%', #{keyword}, '%')
             OR flow_name_en LIKE CONCAT('%', #{keyword}, '%'))


        AND trigger_time >= #{startTime}


        AND trigger_time  <=  #{endTime}


ORDER BY trigger_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM openplatform_v2_cp_execution_record_t


        AND flow_id = #{flowId}


        AND app_id = #{appId}


        AND status = #{status}


        AND trigger_type = #{triggerType}


        AND (flow_name_cn LIKE CONCAT('%', #{keyword}, '%')
             OR flow_name_en LIKE CONCAT('%', #{keyword}, '%'))


        AND trigger_time >= #{startTime}


        AND trigger_time  <=  #{endTime}

SELECT COUNT(*)
FROM openplatform_v2_cp_execution_record_t
WHERE flow_id = #{flowId}

mapper.delete:
DELETE FROM openplatform_v2_cp_execution_record_t
WHERE trigger_time  <  #{beforeTime}
LIMIT #{limit}

DELETE FROM openplatform_v2_cp_execution_record_t
WHERE id IN (
    SELECT id FROM (
        SELECT id FROM openplatform_v2_cp_execution_record_t
        WHERE flow_id = #{flowId}
        ORDER BY create_time ASC
        LIMIT #{limit}
    ) AS tmp
)
